// ── Node 3: 투구 diff 감지 (피치클락 8초 폴링) ──────────────────────────────
// 정적 데이터로 폴링 사이클 간 상태 유지 (n8n 재시작 시 초기화됨)
const staticData = $getWorkflowStaticData('global');
const feed       = $input.first().json;

const gameState   = feed.gameData?.status?.abstractGameState;
const currentPlay = feed.liveData?.plays?.currentPlay;
const linescore   = feed.liveData?.linescore;

// ① 현재 타석 + 누적 투구 수 기반 고유 pitch ID 생성
const atBatIdx    = currentPlay?.about?.atBatIndex ?? -1;
const pitchEvents = (currentPlay?.playEvents ?? []).filter(e => e.isPitch);
const pitchCount  = pitchEvents.length;
const pitchId     = `${atBatIdx}-${pitchCount}`;
const lastPitchId = staticData.lastPitchId ?? '';

// ② 신규 투구 없음 → IF Node에서 FALSE 분기
if (pitchCount === 0 || pitchId === lastPitchId) {
  return [{
    json: {
      has_new_pitch: false,
      game_state:    gameState,
      game_pk:       feed.gamePk
    }
  }];
}

// ③ 신규 투구 감지 → 수비팀 야수 ID 추출
const latestPitch = pitchEvents[pitchEvents.length - 1];
const boxscore    = feed.liveData?.boxscore;
const halfInning  = currentPlay?.about?.halfInning ?? 'top';
const defSide     = halfInning === 'top' ? 'home' : 'away';
const defTeam     = boxscore?.teams?.[defSide];

let   catcherId  = null;
const fielderIds = [];
for (const [, player] of Object.entries(defTeam?.players ?? {})) {
  const posCode = player?.position?.code;
  const id      = player?.person?.id;
  if (!id) continue;
  if (posCode === '2') catcherId = id;
  const posNum = parseInt(posCode);
  if (posNum >= 3 && posNum <= 9) fielderIds.push(id);
}

// ④ 상태 저장 (다음 폴링에서 비교용)
staticData.lastPitchId = pitchId;

return [{
  json: {
    has_new_pitch:  true,
    game_pk:        feed.gamePk,
    at_bat_number:  atBatIdx,
    pitch_number:   latestPitch.pitchNumber,
    pitcher_id:     currentPlay?.matchup?.pitcher?.id,
    batter_id:      currentPlay?.matchup?.batter?.id,
    catcher_id:     catcherId,
    fielder_ids:    fielderIds.slice(0, 7),
    inning:         linescore?.currentInning,
    balls:          currentPlay?.count?.balls,
    strikes:        currentPlay?.count?.strikes,
    outs:           currentPlay?.count?.outs,
    on_1b:          linescore?.offense?.first  ? 1 : 0,
    on_2b:          linescore?.offense?.second ? 1 : 0,
    on_3b:          linescore?.offense?.third  ? 1 : 0,
    game_state:     gameState
  }
}];

